        Map<Integer, Map<String, Boolean>> mapByU = visited.computeIfAbsent((int) mask, k -> new HashMap<>());
        Map<String, Boolean> stringMap = mapByU.computeIfAbsent(i, k -> new HashMap<>());
        stringMap.put(s, true);
        queue.offer(new SimpleEntry<>((int) mask, state));
    }

    while (!queue.isEmpty()) {
        Map.Entry<Integer, long[]> entry = queue.poll();
        int mask = (int)(long) entry.getKey();
        long[] stateVal = entry.getValue();
        int u = (int) stateVal[1];
        int v = (int) stateVal[2];
        int len = (int) stateVal[3];
        String pathString = reconstructPath(mask, u, v, graph, label);

        for (int w : graph.get(u)) {
            if ((mask & (1L << w)) == 0) {
                long newMask = mask | (1L << w);
                char c = label.charAt(w);
                String newString = c + pathString;
                boolean isPalindrome = newString.equals(new StringBuilder(newString).reverse().toString());
                if (isPalindrome) {
                    maxLen = Math.max(maxLen, len + 1);
                }
                if (!isVisited((int) newMask, w, v, newString, visited)) {
                    markVisited((int) newMask, w, v, newString, visited);
                    queue.offer(new SimpleEntry<>((int) newMask, new long[] { newMask, w, v, len + 1 }));
                }
            }
        }

        for (int w : graph.get(v)) {
            if ((mask & (1L << w)) == 0) {
                long newMask = mask | (1L << w);
                char c = label.charAt(w);
                String newString = pathString + c;
                boolean isPalindrome = newString.equals(new StringBuilder(newString).reverse().toString());
                if (isPalindrome) {
                    maxLen = Math.max(maxLen, len + 1);
                }
                if (!isVisited((int) newMask, u, w, newString, visited)) {
                    markVisited((int) newMask, u, w, newString, visited);
                    queue.offer(new SimpleEntry<>((int) newMask, new long[] { newMask, u, w, len + 1 }));
                }
            }
        }
    }

    return maxLen;
}

private static String reconstructPath(long mask, int u, int v, List<List<Integer>> graph, String label) {
    if (u == v) {
        return label.substring(u, u + 1);
    }
    int n = label.length();
    List<Integer> pathList = new ArrayList<>();
    pathList.add(u);
    pathList.add(v);
    Set<Integer> used = new HashSet<>();
    used.add(u);
    used.add(v);
    boolean found = true;
    while (used.size() < Long.bitCount(mask)) {
        found = false;
        int first = pathList.get(0);
        int last = pathList.get(pathList.size() - 1);
        for (int adj : graph.get(first)) {
            if (!used.contains(adj) && (mask & (1L << adj)) != 0) {
                pathList.add(0, adj);
                used.add(adj);
                found = true;
                break;
            }
        }
        if (found) continue;
        for (int adj : graph.get(last)) {
            if (!used.contains(adj) && (mask & (1L << adj)) != 0) {
                pathList.add(adj);
                used.add(adj);
                found = true;
                break;
            }
        }
        if (!found) break;
    }
    StringBuilder sb = new StringBuilder();
    for (int node : pathList) {
        sb.append(label.charAt(node));
    }
    return sb.toString();
}

private static boolean isVisited(int mask, int u, int v, String s, Map<Integer, Map<Integer, Map<String, Boolean>>> visited) {
    if (!visited.containsKey(mask)) 
        return false;
    if (!visited.get(mask).containsKey(u))
        return false;
    if (!visited.get(mask).get(u).containsKey(s))
        return false;
    return true;
}

private static void markVisited(int mask, int u, int v, String s, Map<Integer, Map<Integer, Map<String, Boolean>>> visited) {
    Map<Integer, Map<String, Boolean>> mapByU = visited.computeIfAbsent(mask, k -> new HashMap<>());
    Map<String, Boolean> stringMap = mapByU.computeIfAbsent(u, k -> new HashMap<>());
    stringMap.put(s, true);
}
