public class Solution {
    public static long solve(long n, long[][] edges, String label) {
        int nInt = (int) n;
        if (nInt == 1) {
            return 1;
        }

        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < nInt; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            adj.get(u).add(v);
            adj.get(v).add(u);
        }

        int size = 1 << nInt;
        boolean[][][] dp = new boolean[size][nInt][nInt];

        for (int i = 0; i < nInt; i++) {
            dp[1 << i][i][i] = true;
        }

        for (int i = 0; i < edges.length; i++) {
            int u = (int) edges[i][0];
            int v = (int) edges[i][1];
            if (label.charAt(u) == label.charAt(v)) {
                int mask = (1 << u) | (1 << v);
                dp[mask][u][v] = true;
                dp[mask][v][u] = true;
            }
        }

        int ans = 0;
        for (int mask = 0; mask < size; mask++) {
            int bc = Integer.bitCount(mask);
            if (bc > ans) {
                ans = bc;
            }
            for (int u = 0; u < nInt; u++) {
                if ((mask & (1 << u)) == 0) continue;
                for (int v = 0; v < nInt; v++) {
                    if ((mask & (1 << v)) == 0) continue;
                    if (!dp[mask][u][v]) continue;
                    for (int uPrime : adj.get(u)) {
                        if ((mask & (1 << uPrime)) != 0) continue;
                        for (int vPrime : adj.get(v)) {
                            if ((mask & (1 << vPrime)) != 0) continue;
                            if (uPrime == vPrime) continue;
                            if (label.charAt(uPrime) == label.charAt(vPrime)) {
                                int newMask = mask | (1 << uPrime) | (1 << vPrime);
                                if (!dp[newMask][uPrime][vPrime]) {
                                    dp[newMask][uPrime][vPrime] = true;
                                    dp[newMask][vPrime][uPrime] = true;
                                }
                            }
                        }
                    }
                }
            }
        }

        return ans;
    }
}
