    public static long solve(long n, long[][] edges, String label) {
        int n_int = (int) n;
        boolean[][] adj = new boolean[n_int][n_int];
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            adj[u][v] = true;
            adj[v][u] = true;
        }

        int nmasks = 1 << n_int;
        boolean[][][] dp = new boolean[nmasks][n_int][n_int];
        int best = 0;

        for (int mask = 0; mask < nmasks; mask++) {
            int size = Integer.bitCount(mask);
            if (size == 0) continue;

            for (int i = 0; i < n_int; i++) {
                if (((mask >> i) & 1) == 0) continue;
                for (int j = 0; j < n_int; j++) {
                    if (((mask >> j) & 1) == 0) continue;
                    boolean value = false;
                    if (i == j) {
                        if (size == 1) {
                            value = true;
                        } else {
                            value = false;
                        }
                    } else {
                        if (size == 2) {
                            if (adj[i][j] && label.charAt(i) == label.charAt(j)) {
                                value = true;
                            }
                        } else {
                            if (label.charAt(i) == label.charAt(j)) {
                                int remove = (1 << i) | (1 << j);
                                int inner_mask = mask & ~remove;
                                for (int a = 0; a < n_int; a++) {
                                    if ((inner_mask & (1 << a)) == 0) continue;
                                    for (int b = 0; b < n_int; b++) {
                                        if ((inner_mask & (1 << b)) == 0) continue;
                                        if (adj[i][a] && adj[b][j] && dp[inner_mask][a][b]) {
                                            value = true;
                                            break;
                                        }
                                    }
                                    if (value) break;
                                }
                            }
                        }
                    }
                    dp[mask][i][j] = value;
                    if (value && size > best) {
                        best = size;
                    }
                }
            }
        }

        return best > 0 ? best : 1;
    }
}
