import java.util.*;

public class Solution {
    public static long solve(long n_long, long[][] edges, String label) {
        int n = (int) n_long;
        List<Integer>[] adj = new ArrayList[n];
        for (int i = 0; i < n; i++) {
            adj[i] = new ArrayList<>();
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            adj[u].add(v);
            adj[v].add(u);
        }

        int maxLen = 1;
        int totalStates = 1 << n;
        boolean[][][] visited = new boolean[totalStates][n][n];
        Queue<int[]> queue = new ArrayDeque<>();

        for (int i = 0; i < n; i++) {
            int mask = 1 << i;
            visited[mask][i][i] = true;
            queue.offer(new int[]{mask, i, i});
        }

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            if (label.charAt(u) != label.charAt(v)) continue;
            int mask = (1 << u) | (1 << v);
            if (!visited[mask][u][v]) {
                visited[mask][u][v] = true;
                queue.offer(new int[]{mask, u, v});
                maxLen = Math.max(maxLen, 2);
            }
            if (!visited[mask][v][u]) {
                visited[mask][v][u] = true;
                queue.offer(new int[]{mask, v, u});
                maxLen = Math.max(maxLen, 2);
            }
        }

        while (!queue.isEmpty()) {
            int[] state = queue.poll();
            int mask = state[0];
            int i = state[1];
            int j = state[2];
            for (int u : adj[i]) {
                if ((mask & (1 << u)) != 0) continue;
                for (int v : adj[j]) {
                    if (u == v || (mask & (1 << v)) != 0) continue;
                    if (label.charAt(u) == label.charAt(v)) {
                        int newMask = mask | (1 << u) | (1 << v);
                        if (!visited[newMask][u][v]) {
                            visited[newMask][u][v] = true;
                            int count = Integer.bitCount(newMask);
                            if (count > maxLen) {
                                maxLen = count;
                            }
                            queue.offer(new int[]{newMask, u, v});
                        }
                    }
                }
            }
        }

        return maxLen;
    }
}
